<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Employee Availability</h1><p class="text-muted mb-0">Plan staffing, time off, and limited availability before dispatch becomes a daily guessing contest.</p></div></div>
<div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">Add or Update Availability</h2><form method="post"><?=csrf_field()?><div class="mb-3"><label class="form-label">Employee</label><select name="user_id" class="form-select" required><?php foreach($users as $u):?><option value="<?=e($u['id'])?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="mb-3"><label class="form-label">Date</label><input type="date" name="availability_date" class="form-control" required></div><div class="row g-2"><div class="col"><label class="form-label">Start</label><input type="time" name="start_time" class="form-control"></div><div class="col"><label class="form-label">End</label><input type="time" name="end_time" class="form-control"></div></div><div class="my-3"><label class="form-label">Status</label><select name="status" class="form-select"><option>available</option><option>limited</option><option>unavailable</option><option>time_off</option></select></div><div class="mb-3"><label class="form-label">Notes</label><textarea name="notes" class="form-control"></textarea></div><button class="btn btn-primary w-100">Save Availability</button></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="card-body"><form class="row g-2 mb-3"><div class="col"><input type="date" name="from" value="<?=e($from)?>" class="form-control"></div><div class="col"><input type="date" name="to" value="<?=e($to)?>" class="form-control"></div><div class="col-auto"><button class="btn btn-outline-primary">Filter</button></div></form><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Date</th><th>Employee</th><th>Status</th><th>Hours</th><th>Notes</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['availability_date'])?></td><td><?=e($r['user_name'])?></td><td><span class="badge text-bg-<?=$r['status']==='available'?'success':($r['status']==='limited'?'warning':'secondary')?>"><?=e(str_replace('_',' ',$r['status']))?></span></td><td><?=e(($r['start_time']?:'All day').' - '.($r['end_time']?:''))?></td><td><?=e($r['notes'])?></td></tr><?php endforeach?></tbody></table></div></div></div></div></div>
